import mongoose, { Schema } from "mongoose";
const subjectSchema = new Schema({
    userId: {
        type: Schema.Types.ObjectId,
        ref: "User",
        required: true
    },
    title: {
        type: String,
        required: true,
        trim: true
    },
    isAutoGenerated: {
        type: Boolean,
        default: false
    }
}, { timestamps: true });
subjectSchema.index({
    userId: 1,
    title: 1
});
subjectSchema.set('toJSON', {
    transform: (_doc, ret) => {
        delete ret.__v;
        return ret;
    },
});
const Subject = mongoose.model("Subject", subjectSchema);
export default Subject;
